        s.C(-1.6, 1.3, -0.9, 1.8, 0, 1.85);
        s.S();
        s.M(1.7, 0.1);
        s.C(1.6, 1.3, 0.9, 1.8, 0, 1.85);
        s.S();
        s.M(-1.7, 0.1);
        s.L(1.7, 0.1);
