        s.S();
        s.M(1.75, 3.6);
        s.C(2.15, 2.4, 2.0, 1.0, 1.15, 0.35);
        s.S();
        // 屋根：飛檐反宇
        s.M(-2.9, 0.35);
        s.L(2.9, 0.35);
        s.S();
        s.M(-2.9, 0.35);
        s.C(-2.2, -0.5, -1.0, -0.95, 0, -0.95);
        s.S();
        s.M(2.9, 0.35);
        s.C(2.2, -0.5, 1.0, -0.95, 0, -0.95);
        s.S();
        s.逸(() => {
            s.M(-2.9, 0.35);
            s.Qk(-3.2, 0.1, -3.3, -0.25);
            s.S();
            s.M(2.9, 0.35);
            s.Qk(3.2, 0.1, 3.3, -0.25);
            s.S();
        });
        // 露盤與相輪五重
        s.M(-0.6, -0.95);
        s.L(0.6, -0.95);
